// Alpaca shape parsing
const moversResp   = $('Alpaca Market Movers').first().json;
const snapshotResp = $('Alpaca Watchlist Snapshots').first().json;

const gainers = Array.isArray(moversResp.gainers) ? moversResp.gainers : [];
const losers  = Array.isArray(moversResp.losers)  ? moversResp.losers  : [];

const fmtMover = (m) => ({
  ticker: m.symbol,
  price: m.price,
  change: m.change,
  changePct: typeof m.percent_change === 'number' ? Number(m.percent_change.toFixed(2)) : null,
});

// Snapshot format: { AAPL: {dailyBar:{c,h,l,o,v}, prevDailyBar:{c,...}, latestTrade:{p,...}}, ... }
const watchlist = [];
if (snapshotResp && typeof snapshotResp === 'object') {
  for (const [symbol, snap] of Object.entries(snapshotResp)) {
    if (!snap || typeof snap !== 'object') continue;
    const today = snap.dailyBar?.c ?? snap.latestTrade?.p ?? null;
    const prev  = snap.prevDailyBar?.c ?? null;
    let changePct = null;
    if (today != null && prev != null && prev !== 0) {
      changePct = Number((((today - prev) / prev) * 100).toFixed(2));
    }
    watchlist.push({
      ticker: symbol,
      price: today,
      prevClose: prev,
      changePct,
      volume: snap.dailyBar?.v ?? null,
    });
  }
}

const payload = {
  dateISO: new Date().toISOString().slice(0, 10),
  dateHuman: new Date().toLocaleDateString('tr-TR', { day: '2-digit', month: 'long', year: 'numeric' }),
  topGainers: gainers.map(fmtMover),
  topLosers:  losers.map(fmtMover),
  watchlist,
  apiHealth: {
    moversOk:   gainers.length > 0 || losers.length > 0,
    snapshotOk: watchlist.length > 0,
  },
};

const systemPrompt =
  'Sen profesyonel bir piyasa analistisin. Türkçe, kısa ve eyleme yönelik özetler yazarsın. ' +
  'Çıktın yalnızca temiz HTML olmalı (inline CSS, e-posta uyumlu). ' +
  'Açıklama veya markdown asla kullanma — sadece HTML döndür. ' +
  'Tonlama: net, profesyonel, abartısız.';

const userPrompt = [
  `Tarih: ${payload.dateHuman}`,
  `Veri kaynağı: Alpaca Markets`,
  '',
  'Piyasa verisi (JSON):',
  JSON.stringify(payload, null, 2),
  '',
  'Aşağıdaki şablonu kullanarak HTML üret:',
  '1. Üst başlık (gradient header, mavi tonları): "ABD Piyasa Brifingi — ' + payload.dateHuman + '"',
  '2. "En Çok Kazananlar" tablosu (Sembol, Fiyat $, Değişim %). Yüzdeler için #16a34a yeşil.',
  '3. "En Çok Kaybedenler" tablosu. Yüzdeler için #dc2626 kırmızı.',
  '4. "Watchlist Durumu" tablosu (Sembol, Fiyat $, Önceki Kapanış, Günlük %).',
  '5. "Günün İçgörüleri" başlığı + 3 madde (sektörel tema, dikkat çeken hareket, izlenecek seviye).',
  '6. Disclaimer footer (font-size:11px, color:#6b7280): "Bu bir yatırım tavsiyesi değildir. Veri: Alpaca Markets. Otomatik üretildi."',
  '',
  'Stil kuralları:',
  '- Body: max-width:640px; font-family: -apple-system, system-ui, sans-serif; background:#0f172a; color:#e2e8f0; padding:16px',
  '- Tablolar: width:100%; border-collapse:collapse; thead background:#1e293b',
  '- TR ve TD: padding:8px 12px; border-bottom:1px solid #334155',
  '- Sayılar sağa hizalı (text-align:right)',
  '',
  'Eğer veri yoksa (örn. piyasa kapalı veya API hata): bunu kibarca açıklayan kısa bir HTML mesaj döndür.'
].join('\n');

return [{ json: { ...payload, systemPrompt, userPrompt } }];

const resp = $input.first().json;

// Grok response shape (OpenAI-compatible)
let html = resp?.choices?.[0]?.message?.content ?? null;

// Strip markdown code fences if model wrapped output
if (html) {
  html = html.replace(/^```html\s*\n?/i, '').replace(/\n?```\s*$/i, '').trim();
}

// Fallback if LLM returned nothing or an error
if (!html) {
  const dateHuman = $('Build Market Summary').first().json.dateHuman ?? new Date().toLocaleDateString('tr-TR');
  html = `<div style="font-family:sans-serif;padding:16px;background:#0f172a;color:#e2e8f0;max-width:640px">`
    + `<h2 style="color:#f59e0b">ABD Piyasa Brifingi — ${dateHuman}</h2>`
    + `<p>Üzgünüz, bugün AI özeti üretilemedi. Sebep: ${resp?.error?.message ?? 'Bilinmeyen hata'}.</p>`
    + `<pre style="background:#1e293b;padding:8px;border-radius:4px;font-size:11px;overflow:auto">${JSON.stringify(resp).slice(0, 500)}</pre>`
    + `</div>`;
}

return [{
  json: {
    html,
    model: resp?.model ?? 'unknown',
    usage: resp?.usage ?? null,
  }
}];
